// today in Asia/Kuala_Lumpur (GMT+8) — en-CA locale yields YYYY-MM-DD directly
const todayISO = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Kuala_Lumpur', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date());
function addDaysISO(iso, days){const [y,m,d]=iso.split('-').map(Number);const dt=new Date(Date.UTC(y,m-1,d));dt.setUTCDate(dt.getUTCDate()+days);return `${dt.getUTCFullYear()}-${String(dt.getUTCMonth()+1).padStart(2,'0')}-${String(dt.getUTCDate()).padStart(2,'0')}`;}
const target = addDaysISO(todayISO, 3); // 3-day window — keep in sync with n8n-reminder-filter.mjs
const bills = $input.first().json;  // /bills returns the bills[] array
return (Array.isArray(bills)?bills:[]).filter(b => b && b.payment_due_date === target).map(b => ({ json: b }));
